  452: 	/*
  453: 	 * Pick the free zone with lowest index. Zones in the beginning of the
  454: 	 * address space typically provides higher bandwidth than those at the
  455: 	 * end of the address space on HDDs.
  456: 	 */
  457: 	xas_lock(&xas);
  458: 	xas_for_each_marked(&xas, xg, ULONG_MAX, XFS_RTG_FREE)
  459: 		if (atomic_inc_not_zero(&xg->xg_active_ref))
  460: 			goto found;
  461: 	xas_unlock(&xas);
  462: 	return NULL;
  463: 
  464: found:
  465: 	xas_clear_mark(&xas, XFS_RTG_FREE);
  466: 	atomic_dec(&zi->zi_nr_free_zones);
  467: 	xas_unlock(&xas);
