  481: 	if (zi->zi_nr_open_zones >= mp->m_max_open_zones - XFS_OPEN_GC_ZONES)
  482: 		return NULL;
  483: 	if (atomic_read(&zi->zi_nr_free_zones) <
  484: 	    XFS_GC_ZONES - XFS_OPEN_GC_ZONES)
  485: 		return NULL;
