  487: 	/*
  488: 	 * Increment the open zone count to reserve our slot before dropping
  489: 	 * zi_open_zones_lock.
  490: 	 */
  491: 	zi->zi_nr_open_zones++;
  492: 	spin_unlock(&zi->zi_open_zones_lock);
